mapper.update:
UPDATE version
SET is_delete = 'F1'
WHERE id = #{id}

mapper.select:
SELECT v.id, v.name, v.project_id, v.description, v.start_date, v.end_date, alter_common_code(v.status) AS status_name, alter_common_code(v.is_share) AS is_share_name, v.status, v.is_share, CASE WHEN p.default_version_id = v.id THEN 1 ELSE 0 END AS is_default FROM version v LEFT JOIN project p ON v.project_id = p.id WHERE v.is_delete = 'F0' AND ( v.project_id = #{projectId} OR ( v.project_id IN ( SELECT parent_id FROM project START WITH id = #{projectId} CONNECT BY NOCYCLE PRIOR parent_id = id) AND v.is_share = 'O1' ) )
AND v.id = #{id}
AND v.status = #{status}
ORDER BY v.id ASC
